{
  "mode": "method",
  "tests": [
    {
      "name": "valid_candidate",
      "input": {
        "years_of_experience": 12,
        "languages": ["English", "Portuguese"],
        "certifications": ["LSA"],
        "availability": "immediate",
        "time_zone": "US/Brazil"
      },
      "output": "true",
      "notes": "Valid candidate with required experience and certifications."
    },
    {
      "name": "missing_language",
      "input": {
        "years_of_experience": 10,
        "languages": ["English"],
        "certifications": [],
        "availability": "immediate",
        "time_zone": "US/Brazil"
      },
      "output": "false",
      "notes": "Candidate lacks proficiency in Portuguese."
    },
    {
      "name": "insufficient_experience",
      "input": {
        "years_of_experience": 5,
        "languages": ["English", "Portuguese"],
        "certifications": [],
        "availability": "immediate",
        "time_zone": "US/Brazil"
      },
      "output": "false",
      "notes": "Candidate does not meet the 10+ years experience requirement."
    },
    {
      "name": "excessive_availability",
      "input": {
        "years_of_experience": 15,
        "languages": ["English", "Portuguese"],
        "certifications": ["LSA"],
        "availability": "not immediate",
        "time_zone": "US/Brazil"
      },
      "output": "false",
      "notes": "Candidate is not immediately available."
    },
    {
      "name": "valid_candidate_no_certification",
      "input": {
        "years_of_experience": 11,
        "languages": ["English", "Portuguese"],
        "certifications": [],
        "availability": "immediate",
        "time_zone": "US/Brazil"
      },
      "output": "true",
      "notes": "Candidate has sufficient experience despite lacking certification."
    },
    {
      "name": "valid_candidate_with_edge_time_zone",
      "input": {
        "years_of_experience": 10,
        "languages": ["English", "Portuguese"],
        "certifications": [],
        "availability": "immediate",
        "time_zone": "Brazil"
      },
      "output": "true",
      "notes": "Candidate is in Brazil, which is acceptable for time zone overlap."
    },
    {
      "name": "invalid_time_zone",
      "input": {
        "years_of_experience": 10,
        "languages": ["English", "Portuguese"],
        "certifications": [],
        "availability": "immediate",
        "time_zone": "Europe"
      },
      "output": "false",
      "notes": "Candidate is in an invalid time zone."
    },
    {
      "name": "edge_case_zero_experience",
      "input": {
        "years_of_experience": 0,
        "languages": ["English", "Portuguese"],
        "certifications": [],
        "availability": "immediate",
        "time_zone": "US/Brazil"
      },
      "output": "false",
      "notes": "Candidate has no experience, which is unacceptable."
    }
  ],
  "assumptions": "Candidates must meet all requirements to be considered valid.",
  "notes": "Ensure to validate both experience and language proficiency."
}
